from __future__ import annotations

import ssl
import typing

from .._exceptions import ReadError
from .base import (
    SOCKET_OPTION,
    AsyncNetworkBackend,
    AsyncNetworkStream,
    NetworkBackend,
    NetworkStream,
)


class MockSSLObject:
    def __init__(self, http2: bool):
        """Create a mock SSL object that can report ALPN protocol selection."""
        self._http2 = http2

    def selected_alpn_protocol(self) -> str:
        """Return the selected ALPN protocol for this mock SSL object."""
        return "h2" if self._http2 else "http/1.1"


class MockStream(NetworkStream):
    def __init__(self, buffer: list[bytes], http2: bool = False) -> None:
        """Initialize a mock synchronous network stream.

        The buffer is a list of byte chunks that will be returned by read().
        """
        self._buffer = buffer
        self._http2 = http2
        self._closed = False

    def read(self, max_bytes: int, timeout: float | None = None) -> bytes:
        """Read up to max_bytes from the internal buffer.

        This mock ignores max_bytes and timeout, and returns the next chunk or b''.
        """
        if self._closed:
            raise ReadError("Connection closed")
        if not self._buffer:
            return b""
        return self._buffer.pop(0)

    def write(self, buffer: bytes, timeout: float | None = None) -> None:
        """Write data to the stream (no-op for the mock)."""
        pass

    def close(self) -> None:
        """Close the stream so further reads raise ReadError."""
        self._closed = True

    def start_tls(
        self,
        ssl_context: ssl.SSLContext,
        server_hostname: str | None = None,
        timeout: float | None = None,
    ) -> NetworkStream:
        """Start TLS on the stream and return a stream that represents the TLS layer.

        For the mock this simply returns self.
        """
        return self

    def get_extra_info(self, info: str) -> typing.Any:
        """Return extra information about the stream (supports 'ssl_object')."""
        return MockSSLObject(http2=self._http2) if info == "ssl_object" else None

    def __repr__(self) -> str:
        """Return the representation of the mock stream."""
        return "<httpcore.MockStream>"


class MockBackend(NetworkBackend):
    def __init__(self, buffer: list[bytes], http2: bool = False) -> None:
        """Create a mock synchronous network backend with a shared buffer."""
        self._buffer = buffer
        self._http2 = http2

    def connect_tcp(
        self,
        host: str,
        port: int,
        timeout: float | None = None,
        local_address: str | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> NetworkStream:
        """Open a mock TCP connection and return a MockStream instance."""
        return MockStream(list(self._buffer), http2=self._http2)

    def connect_unix_socket(
        self,
        path: str,
        timeout: float | None = None,
        socket_options: typing.Iterable[SOCKET_OPTION] | None = None,
    ) -> NetworkStream:
        """Open a mock UNIX socket connection and return a MockStream instance."""
        return MockStream(list(self._buffer), http2=self._http2)

    def sleep(self, seconds: float) -> None:
        """Sleep for the given number of seconds (no-op for the mock)."""
        pass


class AsyncMockStream(AsyncNetworkStream):
    def __init__(self, buffer: list[bytes], http2: bool = False) -> None:
        """Initialize a mock asynchronous network stream.

        The buffer is a list of byte chunks that will be returned by read().
        """
        self._buffer = buffer
        self._http2 = http2
        self._closed = False

    async def read(self, max_bytes: int, timeout: float | None = None) -> bytes:
        """Asynchronously read up to max_bytes from the internal buffer.

        This mock ignores max_bytes and timeout, and returns the next chunk or b''.
        """
        if self._closed:
            raise ReadError("Connection closed")
        if not self._buffer:
            return b""
        return self._buffer.pop(0)

    async def write(self, buffer: bytes, timeout: float | None = None) -> None:
        """Asynchronously write data to the stream (no-op for the mock)."""
        pass

    async def aclose(self) -> None:
        """Asynchronously close the stream so further reads raise ReadError."""
        self._closed = True

    async def start_tls(
        self,
        ssl_context: ssl.SSLContext,
        server_hostname: str | None = None,
        timeout: float | None = None,
    ) -> AsyncNetworkStream:
        """Start TLS on the stream and return a stream that represents the TLS layer.

        For the mock this simply returns self.
        """
        return self

    def get_extra_info(self, info: str) -> typing.Any:
        """Return extra information about the stream (supports 'ssl_object')."""
        return MockSSLObject(http2=self._http2) if info == "ssl_object" else None

    def __repr__(self) -> str:
        """Return the representation of the async mock stream."""
        return "<httpcore.AsyncMockStream>"


